function  fPlot3DEfld(e1,x,y,z,labels,figH,varargin)%% function plot 3D e-field%% [e1,x,y,lmbNm,omgFs] = fReadPhicoreH5(fNam,dispL,figL)%% e1: 3d array of e-filed (y,x,z)% x: x % y: y % z: z% labels:% figH: figure handle% varargin: roi info, [x1 x2 y1 y2 z1 z2]%% Written by Kei Nakamura%% 2018/11/30: created%%% main bodyif nargin==7    roi = varargin{1};    roix = roi(1:2);    [~,indx(1)] = min(abs(x-roix(1)));    [~,indx(2)] = min(abs(x-roix(2)));    roiy = roi(3:4);    [~,indy(1)] = min(abs(y-roiy(1)));    [~,indy(2)] = min(abs(y-roiy(2)));    roiz = roi(5:6);    [~,indz(1)] = min(abs(z-roiz(1)));    [~,indz(2)] = min(abs(z-roiz(2)));    roiL = 1;           % ROI LOGICelse    roiL = 0;endset(0,'CurrentFigure',figH)% e-field in 1De1x = squeeze(mean(mean(e1,3)));e1x = e1x/max(abs(e1x));e1y = squeeze(mean(mean(e1,3),2));e1y = e1y/max(abs(e1y));e1z = squeeze(mean(mean(e1)));e1z = e1z/max(abs(e1z));% intensity in 2Di1 = abs(e1).^2;    % intensityi1XZ = squeeze(mean(i1,1));i1XZ = i1XZ/max(max(i1XZ));i1YZ = squeeze(mean(i1,2));i1YZ = i1YZ/max(max(i1YZ));i1YX = squeeze(mean(i1,3));i1YX = i1YX/max(max(i1YX));subplot(2,3,1)pcolor(x,y,i1YX)if roiL==1    axis([roix roiy])endshading interptitle('intensity, x-y')xlabel(labels{1})ylabel(labels{2})set(gca,'fontsize',14);subplot(2,3,2)pcolor(z,y,i1YZ)if roiL==1    axis([roiz roiy])endshading interptitle('intensity, z-y')xlabel(labels{3})ylabel(labels{2})set(gca,'fontsize',14);subplot(2,3,3)pcolor(z,x,i1XZ)if roiL==1    axis([roiz roix])endshading interptitle('intensity, x-z')xlabel(labels{3})ylabel(labels{1})set(gca,'fontsize',14);subplot(2,3,4)if roiL==1    plotcmplxV2(x(indx(1):indx(2)),e1x(indx(1):indx(2)));else    plotcmplxV2(x,e1x);endtitle('intensity x')xlabel(labels{1})set(gca,'fontsize',14);subplot(2,3,5)if roiL==1    plotcmplxV2(y(indy(1):indy(2)),e1y(indy(1):indy(2)));else    plotcmplxV2(y,e1y);endtitle('intensity y')xlabel(labels{2})set(gca,'fontsize',14);subplot(2,3,6)if roiL==1    plotcmplxV2(z(indz(1):indz(2)),e1z(indz(1):indz(2)));else    plotcmplxV2(z,e1z);endtitle('intensity z')xlabel(labels{3})set(gca,'fontsize',14);
